fn visual_rows(line: &str, width: u16) -> u16 {
    visual_row_count(line, width).min(usize::from(u16::MAX)) as u16
}

fn visual_row_count(line: &str, width: u16) -> usize {
    let width = usize::from(width.max(1));
    let len = line.chars().count().min(usize::from(u16::MAX));
    (len / width).saturating_add(1)
}

fn cursor_char_count(text: &str, cursor: usize) -> usize {
    text.char_indices()
        .take_while(|(index, _)| *index < cursor)
        .count()
}

fn visible_content(
    content: &str,
    width: u16,
    height: u16,
    scroll_rows: usize,
    prompt_start_line: Option<usize>,
) -> VisibleRightContent {
    let height = usize::from(height);
    let split = prompt_start_line
        .and_then(|line| split_chat_prompt_at_line(content, line))
        .or_else(|| split_chat_prompt(content));
    let Some((history, prompt)) = split else {
        return VisibleRightContent {
            text: tail_visible_content(content, width, height, scroll_rows),
            prompt_start_line: None,
        };
    };

    let prompt_rows = visual_row_count(prompt, width);
    let history_height = height.saturating_sub(prompt_rows).max(1);
    let visible_history = tail_visible_content(history, width, history_height, scroll_rows);
    if visible_history.is_empty() {
        VisibleRightContent {
            text: prompt.to_string(),
            prompt_start_line: Some(0),
        }
    } else {
        let prompt_start_line = pane_text_lines(&visible_history).len();
        VisibleRightContent {
            text: format!("{visible_history}\n{prompt}"),
            prompt_start_line: Some(prompt_start_line),
        }
    }
}

